  --muted:#767676; --border:#E8E8E8; --accent:#CC0019; --accent-h:#E8001C;
  --gold:#C8962B; --font:'Outfit',-apple-system,system-ui,sans-serif;
  --r-sm:8px; --r-md:14px; --r-lg:20px; --cmax:1200px;
}
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
html{scroll-behavior:smooth;}
body{background:var(--bg);color:var(--fg);font-family:var(--font);font-size:16px;line-height:1.5;-webkit-font-smoothing:antialiased;overflow-x:hidden;}
a{color:inherit;text-decoration:none;}
button{font-family:var(--font);cursor:pointer;}
.wrap{max-width:var(--cmax);margin:0 auto;padding:0 24px;}

/* NAV */
.nav{position:sticky;top:0;z-index:200;background:rgba(255,255,255,.97);backdrop-filter:blur(14px);border-bottom:1px solid var(--border);}
.nav-inner{display:flex;align-items:center;height:64px;}
.nav-logo{display:flex;align-items:center;gap:10px;font-weight:800;font-size:15px;letter-spacing:.06em;text-transform:uppercase;flex-shrink:0;margin-right:auto;color:var(--fg);}
.nav-links{display:flex;align-items:center;gap:2px;list-style:none;}
.nav-links a{display:block;padding:6px 13px;font-size:14px;font-weight:500;color:var(--muted);border-radius:var(--r-sm);transition:color .15s,background .15s;}
.nav-links a:hover,.nav-links a.act{color:var(--fg);background:#F0F0F0;}
.nav-actions{display:flex;align-items:center;gap:4px;margin-left:14px;}
.icon-btn{background:none;border:none;color:var(--muted);padding:8px;border-radius:var(--r-sm);display:flex;align-items:center;transition:color .15s,background .15s;}
.icon-btn:hover{color:var(--fg);background:#F0F0F0;}
.cart-wrap{position:relative;}
.cart-badge{position:absolute;top:0;right:0;min-width:18px;height:18px;background:var(--accent);color:#fff;font-size:10px;font-weight:700;border-radius:9px;padding:0 4px;display:flex;align-items:center;justify-content:center;transform:translate(5px,-3px);transition:transform .2s;pointer-events:none;}
.cart-badge.hidden{display:none;}
.btn-pedir{background:var(--accent);color:#fff;border:none;border-radius:var(--r-sm);padding:9px 22px;font-size:14px;font-weight:700;margin-left:8px;transition:background .15s,transform .1s;white-space:nowrap;}
.btn-pedir:hover{background:var(--accent-h);transform:translateY(-1px);}
.hamburger{display:none;background:none;border:none;color:var(--fg);padding:6px;margin-left:12px;border-radius:var(--r-sm);}

/* MOBILE MENU */
.mob-menu{display:none;position:fixed;inset:0;z-index:300;background:var(--surface);flex-direction:column;padding:24px;overflow-y:auto;}
.mob-menu.open{display:flex;}
.mob-menu-head{display:flex;align-items:center;justify-content:space-between;margin-bottom:40px;}
.mob-links{list-style:none;display:flex;flex-direction:column;}
.mob-links a{display:block;font-size:26px;font-weight:800;padding:16px 0;border-bottom:1px solid var(--border);color:var(--fg);transition:color .15s;}
.mob-links a:hover{color:var(--accent);}
.close-btn{background:none;border:none;color:var(--fg);padding:8px;font-size:22px;line-height:1;border-radius:var(--r-sm);display:flex;align-items:center;transition:background .15s;}
.close-btn:hover{background:#F0F0F0;}

